function getNestedValue(obj: Record<string, string>, key: string): string {
  return obj[key] ?? key
}

export function useTranslation() {
  const lang = ref<string>('en')

  function t(key: string, replacements?: Record<string, string>): string {
    const locale = translations[lang.value] ?? translations['en']
    let str = getNestedValue(locale!, key)
    if (replacements) {
      for (const [k, v] of Object.entries(replacements)) {
        str = str.replace(new RegExp(`{${k}}`, 'g'), v)
      }
    }
    return str
  }

  function setLang(newLang: string) {
    lang.value = newLang
  }

  return { t, lang: readonly(lang), setLang }
}
